        // Move to adjacent indices
        int[] neighbors = {current - 1, current + 1};
        for (int neighbor : neighbors) {
            if (neighbor >= 0 && neighbor < n && !visited[neighbor]) {
                visited[neighbor] = true;
                steps[neighbor] = steps[current] + 1;
                queue.offer(neighbor);
            }
